const fs = require('fs');
const readline = require('readline');
const path = require('path');

const logPath = "C:\\Users\\JAAN MD\\.gemini\\antigravity\\brain\\454db598-ba4d-48a3-bfff-24a5ccaed571\\.system_generated\\logs\\transcript_full.jsonl";

async function restore() {
  const fileStream = fs.createReadStream(logPath);
  const rl = readline.createInterface({
    input: fileStream,
    crlfDelay: Infinity
  });

  let foundContent = null;

  for await (const line of rl) {
    if (line.includes('globals.css') && line.includes('glass-card-component')) {
      // Let's parse this JSON line
      try {
        const obj = JSON.parse(line);
        // Look inside content or tool_calls or output
        const text = JSON.stringify(obj);
        if (text.includes('glass-card-component') && text.includes('btn-electric')) {
          console.log("Found a candidate line!");
          // Let's see if this has a large chunk of css
          // We can write it to a temp file to inspect
          fs.writeFileSync('candidate.json', line);
        }
      } catch (e) {
        // ignore parsing errors
      }
    }
  }
}

restore();
